【将json字符串转成多列的函数】WITH      cte_base_i18n_lang_dict AS (SELECT explode(udf.read_json(zh_cn)) AS j_zh_cn                                FROM stg.stg_base_i18n_lang_dict                                WHERE dt = &#x27;2025-10-12&#x27;                                  AND delete_flag = &#x27;0&#x27;                                  AND code in (&#x27;enum_inventory_BillTypeInEnum&#x27;, &#x27;enum_inventory_BillTypeOutEnum&#x27;,                                               &#x27;enum_AdjustBillTypeEnum&#x27;)                                  AND type = &#x27;2&#x27;                                  AND state = &#x27;0&#x27;),    -- 处理json    cte_i18 AS (SELECT get_json_object(j_zh_cn, &#x27;$.code&#x27;) AS code, get_json_object(j_zh_cn, &#x27;$.desc&#x27;) AS desc                FROM cte_base_i18n_lang_dict)SELECT * FROM cte_i18

